import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Courses from './pages/Courses';
import Attendance from './pages/Attendance';
import Grades from './pages/Grades';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/courses' element={<Courses />} />
        <Route path='/attendance' element={<Attendance />} />
        <Route path='/grades' element={<Grades />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const style = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#0f172a' : '#64748b',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>Student Portal</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={style}>Home</NavLink>
          <NavLink to='/courses' style={style}>Courses</NavLink>
          <NavLink to='/attendance' style={style}>Attendance</NavLink>
          <NavLink to='/grades' style={style}>Grades</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function StatsCard({ title, value }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <p style={{ margin: '0 0 8px 0', color: '#64748b' }}>{title}</p>
      <h3 style={{ margin: 0 }}>{value}</h3>
    </div>
  );
}

import React from 'react';
import StatsCard from '../components/StatsCard';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Welcome back</h1>
      <p style={{ color: '#64748b' }}>Track courses, attendance, and academic performance from one place.</p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '18px', marginTop: '24px' }}>
        <StatsCard title='Enrolled Courses' value='5' />
        <StatsCard title='Attendance' value='88%' />
        <StatsCard title='Current GPA' value='3.52' />
      </div>
    </div>
  );
}

import React from 'react';

const courses = [
  { id: 1, code: 'CS101', name: 'Programming Fundamentals' },
  { id: 2, code: 'CS205', name: 'Database Systems' },
  { id: 3, code: 'AI301', name: 'Artificial Intelligence' }
];

export default function Courses() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Courses</h1>
      <div style={{ display: 'grid', gap: '14px' }}>
        {courses.map(course => (
          <div key={course.id} style={{ border: '1px solid #e2e8f0', borderRadius: '12px', padding: '16px' }}>
            <strong>{course.code}</strong>
            <p style={{ margin: '6px 0 0 0' }}>{course.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

import React from 'react';

const records = [
  { id: 1, course: 'Programming Fundamentals', percentage: 92 },
  { id: 2, course: 'Database Systems', percentage: 85 },
  { id: 3, course: 'Artificial Intelligence', percentage: 88 }
];

export default function Attendance() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Attendance</h1>
      <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e2e8f0' }}>
        <thead style={{ background: '#f8fafc' }}>
          <tr>
            <th style={{ padding: '12px', textAlign: 'left' }}>Course</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Attendance %</th>
          </tr>
        </thead>
        <tbody>
          {records.map(record => (
            <tr key={record.id}>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{record.course}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{record.percentage}%</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

import React from 'react';

const grades = [
  { id: 1, course: 'Programming Fundamentals', grade: 'A' },
  { id: 2, course: 'Database Systems', grade: 'B+' },
  { id: 3, course: 'Artificial Intelligence', grade: 'A-' }
];

export default function Grades() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Grades</h1>
      <div style={{ display: 'grid', gap: '14px' }}>
        {grades.map(item => (
          <div key={item.id} style={{ border: '1px solid #e2e8f0', borderRadius: '12px', padding: '16px', display: 'flex', justifyContent: 'space-between' }}>
            <span>{item.course}</span>
            <strong>{item.grade}</strong>
          </div>
        ))}
      </div>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/courses')
def get_courses():
    return jsonify({
        'courses': [
            {'id': 1, 'course_code': 'CS101', 'course_name': 'Programming Fundamentals'},
            {'id': 2, 'course_code': 'CS205', 'course_name': 'Database Systems'},
            {'id': 3, 'course_code': 'AI301', 'course_name': 'Artificial Intelligence'}
        ]
    })

@app.route('/api/attendance')
def get_attendance():
    return jsonify({
        'attendance': [
            {'id': 1, 'course_name': 'Programming Fundamentals', 'attendance_percentage': 92},
            {'id': 2, 'course_name': 'Database Systems', 'attendance_percentage': 85},
            {'id': 3, 'course_name': 'Artificial Intelligence', 'attendance_percentage': 88}
        ]
    })

@app.route('/api/grades')
def get_grades():
    return jsonify({
        'grades': [
            {'id': 1, 'course_name': 'Programming Fundamentals', 'grade': 'A'},
            {'id': 2, 'course_name': 'Database Systems', 'grade': 'B+'},
            {'id': 3, 'course_name': 'Artificial Intelligence', 'grade': 'A-'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
